/****                                Views                                 ****/
/******************************************************************************/


/* View: VIEW_ACESSO */
CREATE VIEW VIEW_ACESSO(
    IDUSUARIO,
    COD_SETOR,
    PODE_RECEPCIONAR,
    NOME,
    NOME_COMPLETO,
    NOME_SETOR,
    CODIGO_USUARIO,
    ATIVO,
    ACESSO_BOTAO_COPIAR)
AS
select
ACESSO.IDUSUARIO,
ACESSO.COD_SETOR,
ACESSO.PODE_RECEPCIONAR,
psw_usuarios.NOME,
COALESCE(psw_usuarios.NOME_COMPLETO,psw_usuarios.NOME) NOME_COMPLETO,
SETOR.NOME_SETOR,
SECRETARIA.CODIGO_USUARIO  PROTOCOLO,
SETOR.ATIVO,
ACESSO.ACESSO_BOTAO_COPIAR

FROM ACESSO JOIN PSW_USUARIOS
ON (ACESSO.IDUSUARIO = psw_usuarios.IDUSUARIO)
JOIN SETOR
ON (ACESSO.COD_SETOR = SETOR.COD_SETOR)
JOIN SECRETARIA
ON (SETOR.COD_SECRETARIA = SECRETARIA.COD_SECRETARIA)
;




