ASDECLARE VARIABLE ID_OPERACAO INTEGER; DECLARE VARIABLE ID_AUDITORIA INTEGER; DECLARE VARIABLE CHAVE_AUDITORIA VARCHAR(150); DECLARE VARIABLE CONTADOR INTEGER; DECLARE VARIABLE VARIAVEL_CONTEXTO VARCHAR(30); DECLARE VARIABLE USUARIO_JAVA VARCHAR(30); DECLARE VARIABLE ID_NA_USUARIO_AUDIT INTEGER; DECLARE VARIABLE ID_NA_SISTEMA_AUDIT INTEGER; BEGIN CONTADOR = 0; ID_NA_USUARIO_AUDIT = NULL;ID_NA_SISTEMA_AUDIT = NULL;SELECT TRIM(SUBSTRING(TRIM(COALESCE(RDB$GET_CONTEXT('USER_SESSION', 'USUARIO_LOGIN'),'')) FROM 1 FOR 30)) AS CONTEUDO FROM RDB$DATABASE INTO VARIAVEL_CONTEXTO; IF ((:VARIAVEL_CONTEXTO IS NULL) OR (TRIM(:VARIAVEL_CONTEXTO) = '')) THEN VARIAVEL_CONTEXTO = USER;IF (INSERTING) THEN BEGIN ID_OPERACAO = 1; CHAVE_AUDITORIA = NEW.IDUSUARIO || ';' || NEW.COD_SETOR; ID_NA_USUARIO_AUDIT = NEW.ID_NA_USUARIO_AUDITORIA; ID_NA_SISTEMA_AUDIT = NEW.ID_NA_SISTEMA_AUDITORIA; ENDELSE IF (UPDATING) THEN BEGIN ID_OPERACAO = 2; CHAVE_AUDITORIA = NEW.IDUSUARIO || ';' || NEW.COD_SETOR; ID_NA_USUARIO_AUDIT = NEW.ID_NA_USUARIO_AUDITORIA; ID_NA_SISTEMA_AUDIT = NEW.ID_NA_SISTEMA_AUDITORIA; ENDELSE IF (DELETING) THEN BEGIN ID_OPERACAO = 3; CHAVE_AUDITORIA = OLD.IDUSUARIO || ';' || OLD.COD_SETOR; ID_NA_USUARIO_AUDIT = OLD.ID_NA_USUARIO_AUDITORIA; ID_NA_SISTEMA_AUDIT = OLD.ID_NA_SISTEMA_AUDITORIA; ENDIF (ID_NA_USUARIO_AUDIT IS NOT NULL) THEN BEGIN SELECT U.LOGIN FROM NA_USUARIO U WHERE U.ID = :ID_NA_USUARIO_AUDIT INTO :USUARIO_JAVA;IF (USUARIO_JAVA IS NOT NULL) THEN VARIAVEL_CONTEXTO = :USUARIO_JAVA; END ID_AUDITORIA = GEN_ID(AUDITORIA_SISTEMA, 1);INSERT INTO AUDITORIA_SISTEMA (COD_AUDITORIA, TABELA, CHAVE_REGISTRO, DATA_AUDITORIA, HORA_AUDITORIA, USUARIO, TIPO_OPERACAO) VALUES (:ID_AUDITORIA, 'ACESSO', :CHAVE_AUDITORIA, 'NOW', 'NOW', :VARIAVEL_CONTEXTO, :ID_OPERACAO); EXECUTE PROCEDURE SP_AUDIT$INSERE_ITEM(:ID_AUDITORIA,:ID_OPERACAO,0,'IDUSUARIO',OLD.IDUSUARIO,NEW.IDUSUARIO,:CONTADOR) RETURNING_VALUES :CONTADOR;EXECUTE PROCEDURE SP_AUDIT$INSERE_ITEM(:ID_AUDITORIA,:ID_OPERACAO,1,'COD_SETOR',OLD.COD_SETOR,NEW.COD_SETOR,:CONTADOR) RETURNING_VALUES :CONTADOR;EXECUTE PROCEDURE SP_AUDIT$INSERE_ITEM(:ID_AUDITORIA,:ID_OPERACAO,2,'PODE_RECEPCIONAR',OLD.PODE_RECEPCIONAR,NEW.PODE_RECEPCIONAR,:CONTADOR) RETURNING_VALUES :CONTADOR;EXECUTE PROCEDURE SP_AUDIT$INSERE_ITEM(:ID_AUDITORIA,:ID_OPERACAO,3,'ACESSO_BOTAO_COPIAR',OLD.ACESSO_BOTAO_COPIAR,NEW.ACESSO_BOTAO_COPIAR,:CONTADOR) RETURNING_VALUES :CONTADOR;IF (:CONTADOR > 0) THEN BEGINIF (ID_NA_SISTEMA_AUDIT IS NOT NULL) THEN VARIAVEL_CONTEXTO = CAST(:ID_NA_SISTEMA_AUDIT AS VARCHAR(10)); ELSE SELECT TRIM(SUBSTRING(TRIM(COALESCE(RDB$GET_CONTEXT('USER_SESSION', 'SISTEMA_ID'),'')) FROM 1 FOR 30)) AS CONTEUDO FROM RDB$DATABASE INTO VARIAVEL_CONTEXTO;EXECUTE PROCEDURE SP_AUDIT$INSERE_ITEM(:ID_AUDITORIA, :ID_OPERACAO, 4, 'CODIGO DO SISTEMA', NULL, :VARIAVEL_CONTEXTO, :CONTADOR) RETURNING_VALUES :CONTADOR;SELECT TRIM(SUBSTRING(TRIM(COALESCE(RDB$GET_CONTEXT('USER_SESSION', 'SISTEMA_VERSAO'),'')) FROM 1 FOR 30)) AS CONTEUDO FROM RDB$DATABASE INTO VARIAVEL_CONTEXTO;EXECUTE PROCEDURE SP_AUDIT$INSERE_ITEM(:ID_AUDITORIA, :ID_OPERACAO, 5, 'VERSAO DO SISTEMA', NULL, :VARIAVEL_CONTEXTO, :CONTADOR) RETURNING_VALUES :CONTADOR;SELECT TRIM(SUBSTRING(TRIM(COALESCE(RDB$GET_CONTEXT('USER_SESSION', 'TERMINAL_IP'),'')) FROM 1 FOR 30)) AS CONTEUDO FROM RDB$DATABASE INTO VARIAVEL_CONTEXTO;EXECUTE PROCEDURE SP_AUDIT$INSERE_ITEM(:ID_AUDITORIA, :ID_OPERACAO, 6, 'IP DO TERMINAL', NULL, :VARIAVEL_CONTEXTO, :CONTADOR) RETURNING_VALUES :CONTADOR;SELECT TRIM(SUBSTRING(TRIM(COALESCE(RDB$GET_CONTEXT('USER_SESSION', 'TERMINAL_NOME'),'')) FROM 1 FOR 30)) AS CONTEUDO FROM RDB$DATABASE INTO VARIAVEL_CONTEXTO;EXECUTE PROCEDURE SP_AUDIT$INSERE_ITEM(:ID_AUDITORIA, :ID_OPERACAO, 7, 'NOME DO TERMINAL', NULL, :VARIAVEL_CONTEXTO, :CONTADOR) RETURNING_VALUES :CONTADOR;END ELSE DELETE FROM AUDITORIA_SISTEMA WHERE COD_AUDITORIA = :ID_AUDITORIA; IF ((INSERTING OR UPDATING) AND (ID_NA_USUARIO_AUDIT IS NOT NULL OR ID_NA_SISTEMA_AUDIT IS NOT NULL)) THEN UPDATE ACESSO SET ID_NA_USUARIO_AUDITORIA = NULL, ID_NA_SISTEMA_AUDITORIA = NULL  WHERE IDUSUARIO =  NEW.IDUSUARIO AND COD_SETOR =  NEW.COD_SETOR; END
^

