_AUDIT$INSERE_ITEM(:ID_AUDITORIA,:ID_OPERACAO,2,'EMAIL_SMTP',OLD.EMAIL_SMTP,NEW.EMAIL_SMTP,:CONTADOR) RETURNING_VALUES :CONTADOR;EXECUTE PROCEDURE SP_AUDIT$INSERE_ITEM(:ID_AUDITORIA,:ID_OPERACAO,3,'EMAIL_PORT',OLD.EMAIL_PORT,NEW.EMAIL_PORT,:CONTADOR) RETURNING_VALUES :CONTADOR;EXECUTE PROCEDURE SP_AUDIT$INSERE_ITEM(:ID_AUDITORIA,:ID_OPERACAO,4,'EMAIL_SENHA',OLD.EMAIL_SENHA,NEW.EMAIL_SENHA,:CONTADOR) RETURNING_VALUES :CONTADOR;EXECUTE PROCEDURE SP_AUDIT$INSERE_ITEM(:ID_AUDITORIA,:ID_OPERACAO,5,'EMAIL_USUARIO',OLD.EMAIL_USUARIO,NEW.EMAIL_USUARIO,:CONTADOR) RETURNING_VALUES :CONTADOR;EXECUTE PROCEDURE SP_AUDIT$INSERE_ITEM(:ID_AUDITORIA,:ID_OPERACAO,6,'EMAILS_NOTIFICADOS',OLD.EMAILS_NOTIFICADOS,NEW.EMAILS_NOTIFICADOS,:CONTADOR) RETURNING_VALUES :CONTADOR;EXECUTE PROCEDURE SP_AUDIT$INSERE_ITEM(:ID_AUDITORIA,:ID_OPERACAO,7,'DATA_ULTIMO_LOGIN',OLD.DATA_ULTIMO_LOGIN,NEW.DATA_ULTIMO_LOGIN,:CONTADOR) RETURNING_VALUES :CONTADOR;IF (:CONTADOR > 0) THEN BEGINIF (ID_NA_SISTEMA_AUDIT IS NOT NULL) THEN VARIAVEL_CONTEXTO = CAST(:ID_NA_SISTEMA_AUDIT AS VARCHAR(10)); ELSE SELECT TRIM(SUBSTRING(TRIM(COALESCE(RDB$GET_CONTEXT('USER_SESSION', 'SISTEMA_ID'),'')) FROM 1 FOR 30)) AS CONTEUDO FROM RDB$DATABASE INTO VARIAVEL_CONTEXTO;EXECUTE PROCEDURE SP_AUDIT$INSERE_ITEM(:ID_AUDITORIA, :ID_OPERACAO, 8, 'CODIGO DO SISTEMA', NULL, :VARIAVEL_CONTEXTO, :CONTADOR) RETURNING_VALUES :CONTADOR;SELECT TRIM(SUBSTRING(TRIM(COALESCE(RDB$GET_CONTEXT('USER_SESSION', 'SISTEMA_VERSAO'),'')) FROM 1 FOR 30)) AS CONTEUDO FROM RDB$DATABASE INTO VARIAVEL_CONTEXTO;EXECUTE PROCEDURE SP_AUDIT$INSERE_ITEM(:ID_AUDITORIA, :ID_OPERACAO, 9, 'VERSAO DO SISTEMA', NULL, :VARIAVEL_CONTEXTO, :CONTADOR) RETURNING_VALUES :CONTADOR;SELECT TRIM(SUBSTRING(TRIM(COALESCE(RDB$GET_CONTEXT('USER_SESSION', 'TERMINAL_IP'),'')) FROM 1 FOR 30)) AS CONTEUDO FROM RDB$DATABASE INTO VARIAVEL_CONTEXTO;EXECUTE PROCEDURE SP_AUDIT$INSERE_ITEM(:ID_AUDITORIA, :ID_OPERACAO, 10, 'IP DO TERMINAL', NULL, :VARIAVEL_CONTEXTO, :CONTADOR) RETURNING_VALUES :CONTADOR;SELECT TRIM(SUBSTRING(TRIM(COALESCE(RDB$GET_CONTEXT('USER_SESSION', 'TERMINAL_NOME'),'')) FROM 1 FOR 30)) AS CONTEUDO FROM RDB$DATABASE INTO VARIAVEL_CONTEXTO;EXECUTE PROCEDURE SP_AUDIT$INSERE_ITEM(:ID_AUDITORIA, :ID_OPERACAO, 11, 'NOME DO TERMINAL', NULL, :VARIAVEL_CONTEXTO, :CONTADOR) RETURNING_VALUES :CONTADOR;END ELSE DELETE FROM AUDITORIA_SISTEMA WHERE COD_AUDITORIA = :ID_AUDITORIA; IF ((INSERTING OR UPDATING) AND (ID_NA_USUARIO_AUDIT IS NOT NULL OR ID_NA_SISTEMA_AUDIT IS NOT NULL)) THEN UPDATE SIS$COMPLIB SET ID_NA_USUARIO_AUDITORIA = NULL, ID_NA_SISTEMA_AUDITORIA = NULL  WHERE ID =  NEW.ID; END
