/* Trigger: GERA_LOCAL_PROCESSO */
CREATE TRIGGER GERA_LOCAL_PROCESSO FOR PROCESSO
ACTIVE AFTER INSERT POSITION 0
AS
   declare variable ID integer;
   declare variable HOJE TIMESTAMP;
   declare variable SETOR_ORIGEM INTEGER;
   declare variable PRAZO INTEGER;
   declare variable COD_DOCUMENTO INTEGER;
   declare variable P_ID_ASSUNTO INTEGER;
   declare variable P_ORDEM INTEGER;
   declare variable P_COD_SETOR INTEGER;
   declare variable  p_PRAZO    INTEGER;

begin
  /* CONSIDERANDO O USUARIO SEMPRE UM */
  ID=0;

  SELECT MAX(L.sequencial)  FROM LOCALPROCESSO L
  WHERE L.id_registro_processo = NEW.id_registro_processo
  INTO :ID;

  SELECT current_timestamp  FROM RDB$DATABASE
  INTO :HOJE;

  select COD_SETOR, PRAZO from PROCEDIMENTO
  where ID_ASSUNTO = NEW.id_assunto and ORDEM = 1
  INTO :SETOR_ORIGEM, :PRAZO;

  if ((PRAZO = 0) or (PRAZO IS NULL)) then
  BEGIN
    PRAZO = 1;
  END


  if  (((ID IS NULL) OR (ID = 0)) AND (NEW.id_ouvidoria > 0)) then
  BEGIN

    insert into LOCALPROCESSO
    (ID_REGISTRO_PROCESSO, SEQUENCIAL, DATA, COD_SETOR_ORIGEM, HORA,
     FUNCIONARIO_RECEBIMENTO,VISTO, COD_SETOR_DESTINO, NOME_VISTO, PRAZO, ORDEM_PROCEDIMENTO)
    values
    (NEW.id_registro_processo, 1, :HOJE, :setor_origem, :HOJE,
      'OUVIDORIA INTERNET', 'N', :setor_origem,
      '', :PRAZO, 1);

    for Select DR.cod_documento from DOCREQUERIDO  DR
        Where ID_ASSUNTO = NEW.id_assunto
        INTO :COD_DOCUMENTO
    DO
    BEGIN
         insert into PROCESSODOCUMENTO
           (ID_REGISTRO_PROCESSO, COD_DOCUMENTO, ENTREGUE)
         values
           (NEW.id_registro_processo, :COD_DOCUMENTO, 'N');
    END

    for  select P.id_assunto, p.cod_setor, p.ordem, p.prazo from PROCEDIMENTO P
         where ID_ASSUNTO = NEW.id_assunto
         order by ORDEM
         INTO :p_id_assunto,:p_cod_setor,:p_ordem,:p_prazo
    DO
    BEGIN
        insert into PROCESSOPROCEDIMENTO
           (ID_REGISTRO_PROCESSO, ID_ASSUNTO, ORDEM, EXECUTADO, COD_SETOR, PRAZO)
        values
           (NEW.id_registro_processo, :p_id_assunto, :p_ordem, 'N' , :p_cod_setor, :p_prazo);
    END


  END
end
^

/* Trigger: GUIA_REMESSA_ITEM_BI0 */
CREATE TRIGGER GUIA_REMESSA_ITEM_BI0 FOR GUIA_REMESSA_ITEM
ACTIVE BEFORE INSERT POSITION 0
AS
declare variable SEQUENCIAL INTEGER;
begin
    SELECT MAX(SEQUENCIAL) FROM guia_remessa_item
    WHERE COD_REMESSA = NEW.cod_remessa
    INTO :SEQUENCIAL;
    if (SEQUENCIAL IS NULL) then
       SEQUENCIAL = 0;

    NEW.sequencial = SEQUENCIAL + 1;
end
^

