/* Trigger: NA_MENU_BIU */
CREATE TRIGGER NA_MENU_BIU FOR NA_MENU
ACTIVE BEFORE INSERT OR UPDATE POSITION 10
as
declare variable QTDE_PONTO integer;
declare variable COD_MENU varchar(50);
declare variable SCHAVE_ORDENACAO_MENU varchar(200);
declare variable ITEM varchar(50);
declare variable I integer;
begin

  if (new.ID is null or new.ID = 0) then
    new.ID = gen_id(SEQ_NA_MENU, 1);

  COD_MENU = null;
  select first 1 substring(trim(RETORNO) from 1 for 50)
  from SP_FI_SUB_STRING(new.MN_TELA_DESCRICAO, '-', 0)
  into COD_MENU;

  if (COD_MENU is not null) then
  begin

    QTDE_PONTO = 0;
    SCHAVE_ORDENACAO_MENU = '';

    select RETORNO
    from SP_FI_EXISTE_CARACTER(:COD_MENU, '.')
    into QTDE_PONTO;

    if (QTDE_PONTO = 0) then
    begin
      select RETORNA
      from SP_FI_PREENCHE_ZERO(:COD_MENU, 2, 'E')
      into SCHAVE_ORDENACAO_MENU;
    end
    else begin
      I = 0;

      while (I <= QTDE_PONTO) do
      begin

        select first 1 trim(RETORNO)
        from SP_FI_SUB_STRING(:COD_MENU, '.', :I)
        into ITEM;

        select RETORNA
        from SP_FI_PREENCHE_ZERO(:ITEM, 2, 'E')
        into ITEM;

        if (SCHAVE_ORDENACAO_MENU <> '') then
          SCHAVE_ORDENACAO_MENU = substring(SCHAVE_ORDENACAO_MENU || '.' || ITEM from 1 for 50);
        else
          SCHAVE_ORDENACAO_MENU = ITEM;

        I = I + 1;
      end

    end /* else begin */

    new.CHAVE_ORDENACAO_MENU = substring(trim(:SCHAVE_ORDENACAO_MENU) from 1 for 50);

  end /* if (COD_MENU is not null) then*/

end
^

