/* Trigger: NA_USUARIO_AU */
CREATE TRIGGER NA_USUARIO_AU FOR NA_USUARIO
ACTIVE AFTER UPDATE POSITION 0
as
begin

  if (new.ORIGEM_ALTERACAO is not null and new.ORIGEM_ALTERACAO = 'W') then
  begin
    update PSW_USUARIOS set SENHA = new.SENHA, ORIGEM_ALTERACAO = null, CPF = new.CPF_CNPJ, NOME_COMPLETO = new.NOME, EMAIL = new.EMAIL,
                            DATA_NASCIMENTO = new.DATA_NASCIMENTO, ID_NA_USUARIO_SERVER = new.ID_NA_USUARIO_SERVER,
                            DATA_ALTERACAO = new.DATA_ALTERACAO, SENHA_NA_USUARIO_SERVER = NEW.SENHA_NA_USUARIO_SERVER
    where ID_USUARIO_UNIFICADO = new.ID;
  end

  if (new.ORIGEM_ALTERACAO is not null) then
    update NA_USUARIO set ORIGEM_ALTERACAO = null
    where ID = new.ID;

  if ((new.ID_ATOR is not null) and (trim(new.NOME) <> trim(old.NOME))) then
    update NA_ATOR set NOME = trim(new.NOME)
    where ID = new.ID_ATOR;
end
^

