/* Trigger: PSW_USUARIOS_NA_BI */
CREATE TRIGGER PSW_USUARIOS_NA_BI FOR PSW_USUARIOS
ACTIVE BEFORE INSERT POSITION 0
as
begin

  new.LOGIN_ANTERIOR = new.NOME;

  if (new.EMAIL is not null) then
  begin
    if (Trim(new.EMAIL) = '') then
      new.EMAIL = null;
    else
      new.EMAIL = LOWER(new.EMAIL);
  end

  if (new.CPF is not null) then
  begin
    if (Trim(new.CPF) = '') then
      new.CPF = null;
  end

  if (new.IDUSUARIO is null or new.IDUSUARIO = 0) then
    new.IDUSUARIO = gen_id(SEQ_PSW_USUARIOS, 1);
end
^

/* Trigger: PSW_USUARIOS_NA_BU */
CREATE TRIGGER PSW_USUARIOS_NA_BU FOR PSW_USUARIOS
ACTIVE BEFORE UPDATE POSITION 0
AS
BEGIN

  if (new.EMAIL is not null) then
  begin
    if (Trim(new.EMAIL) = '') then
      new.EMAIL = null;
    else
      new.EMAIL = LOWER(new.EMAIL);
  end

  if (new.CPF is not null) then
  begin
    if (Trim(new.CPF) = '') then
      new.CPF = null;
  end

  if ((new.ORIGEM_ALTERACAO = 'D') and ((new.NOME_COMPLETO <> old.NOME_COMPLETO) or
      (new.SENHA <> old.SENHA) or
      (new.NIVELUSUARIO <> old.NIVELUSUARIO) or
      (new.DATA_NASCIMENTO <> old.DATA_NASCIMENTO) or
      (new.EMAIL <> old.EMAIL))) then
  begin
    new.DATA_ALTERACAO = current_timestamp;
  end

END
^

/* Trigger: REPL$4_319_D_3_3 */
CREATE TRIGGER REPL$4_319_D_3_3 FOR ACESSO
ACTIVE AFTER DELETE POSITION 32760
AS
BEGIN
IF (USER <> 'REPL') THEN BEGIN
  INSERT INTO REPL_LOG(REPLNO,PUBDBNO,SUBDBNO,RELATIONNO,REPTYPE,OLDKEY)
  SELECT REPLNO,PUBDBNO,SUBDBNO,RELATIONNO,'D',OLD.IDUSUARIO||'  '||OLD.COD_SETOR
    FROM REPL_SEPARATOR
   WHERE REPLNO=3
     AND PUBDBNO=3
     AND SUBDBNO=4
     AND RELATIONNO=319;
END
END
