/* Trigger: SIS$ERRO_ITEM_BI0 */
CREATE TRIGGER SIS$ERRO_ITEM_BI0 FOR SIS$ERRO_ITEM
ACTIVE BEFORE INSERT POSITION 0
AS 
declare variable Quantidade integer; 
begin
    Quantidade = 0;
    select count(ID_ERRO) from SIS$ERRO_ITEM 
    where ID_ERRO = new.id_erro 
    into :Quantidade; 
    if (Quantidade is null) then 
       Quantidade = 0; 
    new.id_item_erro = Quantidade + 1; 
end
^

/* Trigger: SIS$GEN_ID_BIU */
CREATE TRIGGER SIS$GEN_ID_BIU FOR SIS$GEN_ID
ACTIVE BEFORE INSERT OR UPDATE POSITION 0
as
begin
  if (new.ID is null or new.ID = 0) then
    new.ID = gen_id(SEQ_SIS$GEN_ID, 1);

  new.TABELA = trim(new.TABELA);
  new.FILTRO = COALESCE(trim(new.FILTRO), '');
  new.GEN_ID_NOME = trim(new.GEN_ID_NOME);
  new.CAMPO_ID = trim(new.CAMPO_ID);
end
^

/* Trigger: TGR_AUDIT$_AUDITORIA_TABELA_AU */
CREATE TRIGGER TGR_AUDIT$_AUDITORIA_TABELA_AU FOR NA_AUDITORIA_TABELA
ACTIVE AFTER UPDATE POSITION 32765
AS
DECLARE VARIABLE DROP_TRIGGER CHAR(1);
DECLARE VARIABLE QTDE_PK INTEGER;
BEGIN
  IF ((NEW.NOME <> 'AUDITORIA_SISTEMA') AND (NEW.NOME <> 'AUDITORIA_SISTEMA_ITEM') AND
     (NEW.NOME <> 'NA_AUDITORIA') AND (NEW.NOME <> 'NA_AUDITORIA_ITEM') AND
     ((COALESCE(NEW.AUDIT_INSERT, 'S') <> COALESCE(OLD.AUDIT_INSERT, 'S')) OR
     (COALESCE(NEW.AUDIT_UPDATE, 'S') <> COALESCE(OLD.AUDIT_UPDATE, 'S')) OR
     (COALESCE(NEW.AUDIT_DELETE, 'S') <> COALESCE(OLD.AUDIT_DELETE, 'S')))) THEN
  BEGIN
    SELECT CASE WHEN COUNT(*) > 0 THEN 'S' ELSE 'N' END AS DROP_TRIGGER
    FROM RDB$TRIGGERS T
    WHERE SUBSTRING(T.RDB$TRIGGER_NAME FROM 1 FOR 6) = 'AUDIT$'
    AND T.RDB$RELATION_NAME = NEW.NOME
    INTO :DROP_TRIGGER;
    SELECT COUNT(*) FROM RDB$RELATION_CONSTRAINTS RC
    WHERE RC.RDB$RELATION_NAME = NEW.NOME AND RC.RDB$CONSTRAINT_TYPE = 'PRIMARY KEY'
    INTO QTDE_PK;
    IF (QTDE_PK>0) THEN
      EXECUTE PROCEDURE SP_AUDIT$GERA_TRIGGER(NEW.IDENTIFICADOR, NEW.NOME, :DROP_TRIGGER, NEW.AUDIT_INSERT, NEW.AUDIT_UPDATE, NEW.AUDIT_DELETE);
  END
END
^
SET TERM ; ^



